struct RecoverBSTHelper {
    struct TreeNode* firstIncorrectNode;
    struct TreeNode* secondIncorrectNode;
    struct TreeNode* previousNode;
};

// Function to traverse the tree and find the two nodes that are swapped
void findSwappedNodes(struct RecoverBSTHelper* helper, struct TreeNode* root) {
    if (root == NULL)
        return;

    // In-order traversal: left subtree
    findSwappedNodes(helper, root->left);

    // Check if the current node violates the BST property
    if (helper->firstIncorrectNode == NULL && helper->previousNode->value >= root->value) {
        helper->firstIncorrectNode = helper->previousNode;
    }
    if (helper->firstIncorrectNode != NULL && helper->previousNode->value >= root->value) {
        helper->secondIncorrectNode = root;
    }

    helper->previousNode = root;

    // In-order traversal: right subtree
    findSwappedNodes(helper, root->right);
}

// Function to recover the BST by swapping the values of the two incorrect nodes
