class Solution {
    Node firstNode = null;
    Node secondNode = null;
    Node prevNode = new Node(Integer.MIN_VALUE);

    void traverse(Node root) {
        if (root == null) return;

        traverse(root.left);

        if (firstNode == null && prevNode.val >= root.val) {
            firstNode = prevNode;
        }

        if (firstNode != null && prevNode.val >= root.val) {
            secondNode = root;
        }

        prevNode = root;

        traverse(root.right);
    }

    Node recoverBST(Node root) {
        traverse(root);
        if (firstNode != null && secondNode != null) {
            int temp = firstNode.val;
            firstNode.val = secondNode.val;
            secondNode.val = temp;
        }
        return root;
    }
}

